import{_ as t,o as a,c as r,a3 as d}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Daily CRM summary — Production Report","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Daily CRM summary — Production Report | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/daily-crm-summary"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Daily CRM summary — Production Report | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/daily-crm-summary"}]]},"headers":[],"relativePath":"deployment/daily-crm-summary.md","filePath":"deployment/daily-crm-summary.md","lastUpdated":1784926677000}'),i={name:"deployment/daily-crm-summary.md"};function o(s,e,n,l,c,m){return a(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="daily-crm-summary-—-production-report" tabindex="-1">Daily CRM summary — Production Report <a class="header-anchor" href="#daily-crm-summary-—-production-report" aria-label="Permalink to &quot;Daily CRM summary — Production Report&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td><strong>Branch</strong></td><td><code>feature/daily-crm-summary</code></td></tr><tr><td><strong>Date</strong></td><td>2026-07-23</td></tr><tr><td><strong>Status</strong></td><td><strong>Ready for GA</strong> after migrate + emails worker smoke (Critical/High audit items addressed)</td></tr><tr><td><strong>Repos</strong></td><td>SaaS-Backend, SaaS-Frontend, SaaS-Docs</td></tr></tbody></table><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>At workspace <strong>Daily Reminder Time</strong> (<code>task_reminder_time</code>, default <code>09:00</code> local), <code>crm:send-due-notifications</code> sends mail-only CRM snapshots in addition to the existing task due digest:</p><table tabindex="0"><thead><tr><th>User flag <code>receive_all_users_daily_summary</code></th><th>Email</th></tr></thead><tbody><tr><td><code>false</code></td><td>Personal summary only (skipped when no open CRM work)</td></tr><tr><td><code>true</code></td><td>User-wise team summary only (not both); roster includes only users with activity</td></tr></tbody></table><p>Counts:</p><ul><li><strong>Leads</strong> — open stages only (exclude <code>is_won</code> / <code>is_lost</code>)</li><li><strong>Tasks</strong> — open / in_progress / waiting (exclude completed / cancelled)</li><li><strong>Meetings</strong> — scheduled only; distinct host <strong>or</strong> attendee (creator-only not counted)</li></ul><p>Aggregations run <strong>once per tenant</strong> per command tick. Meeting counts use SQL <code>COUNT(DISTINCT meeting_id)</code>.</p><hr><h2 id="deploy-checklist" tabindex="-1">Deploy checklist <a class="header-anchor" href="#deploy-checklist" aria-label="Permalink to &quot;Deploy checklist&quot;">​</a></h2><ol><li>Deploy Backend + Frontend + Docs from <code>feature/daily-crm-summary</code>.</li><li>Migrate:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre></div><ul><li><code>users.receive_all_users_daily_summary</code> (default <code>false</code>)</li><li><code>daily_summary_deliveries</code> (unique <code>tenant_id, user_id, digest_date, kind</code>)</li></ul></li><li>Confirm scheduler: <code>crm:send-due-notifications</code> every 5 minutes (<code>withoutOverlapping</code>, <code>onOneServer</code>).</li><li>Confirm <code>php artisan queue:work --queue=emails</code> (and <code>queue:restart</code> after deploy).</li><li>Shared cache driver required for <code>onOneServer</code> locks.</li><li>Configure <strong>Settings → Daily Reminder Time</strong>; flag managers with <strong>Receive all-users daily summary</strong> (visibility grant — prefer Owner/Admin).</li><li>Smoke: <ul><li>Past reminder time → personal mail to unflagged user with open CRM work</li><li>Team mail to flagged user (only users with activity)</li><li>Second cron tick → no duplicate</li><li>Ledger <code>queued</code> → <code>sent</code>; stale <code>queued</code> (&gt;45m) reclaimable (max 5 attempts)</li></ul></li><li>Keep scheduler + emails workers healthy through the local reminder window (no midnight catch-up).</li></ol><hr><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Signal</th><th>What to watch</th></tr></thead><tbody><tr><td><code>daily_summary_deliveries.status = queued</code> older than ~45 minutes</td><td>Worker down (auto-reclaim after stale window)</td></tr><tr><td><code>attempts &gt;= 5</code> still <code>failed</code></td><td>Cap reached; investigate SMTP/queue</td></tr><tr><td><code>crm:send-due-notifications</code> duration</td><td>Should stay flat vs user count after aggregate-once fix</td></tr><tr><td>Emails queue depth</td><td>Backlog after reminder time</td></tr></tbody></table><hr><h2 id="audit-remediation-2026-07-23" tabindex="-1">Audit remediation (2026-07-23) <a class="header-anchor" href="#audit-remediation-2026-07-23" aria-label="Permalink to &quot;Audit remediation (2026-07-23)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Status</th></tr></thead><tbody><tr><td>Personal N× full-tenant scans</td><td>Fixed — <code>summarizeUsers()</code> once per tenant</td></tr><tr><td>Meeting PHP hydration</td><td>Fixed — SQL <code>COUNT(DISTINCT)</code> union</td></tr><tr><td>Stale queued / max attempts</td><td>Fixed — 45m reclaim, max 5</td></tr><tr><td>Team zero-activity noise</td><td>Fixed — <code>summarizeActiveUsers()</code></td></tr><tr><td>Deploy / database / Users API docs</td><td>Fixed</td></tr><tr><td>Pest gaps</td><td>Fixed — markSent, suspended, empty, TZ, dedupe, stale reclaim</td></tr><tr><td>Playwright flag toggle</td><td>Added <code>users.daily-summary-flag.spec.ts</code></td></tr><tr><td>RBAC duplicate Edit rows + privacy note</td><td>Fixed</td></tr></tbody></table><hr><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/user-guide/tenant-settings">Tenant settings (user)</a></li><li><a href="/user-guide/tasks">Tasks (user)</a></li><li><a href="/user-guide/tenant-rbac">Tenant RBAC (user)</a></li><li><a href="/api/tenant-v1-users">Tenant Users API</a></li><li><a href="/api/tenant-v1-notifications">Tenant notifications API</a></li><li><a href="/developer-guide/database">Database architecture</a></li><li><a href="/deployment/tasks">Tasks production</a></li><li><a href="/changelog/">Changelog</a></li></ul>',21)])])}const p=t(i,[["render",o]]);export{h as __pageData,p as default};
